function stripCredentials(url) {
    const parsedUrl = new URL(url);
    const { protocol, hostname, pathname, search, hash } = parsedUrl;

    // Remove username and password from the hostname
    const credentialsIndex = hostname.indexOf('@');
    if (credentialsIndex !== -1) {
        const hostnameWithoutCredentials = hostname.substring(credentialsIndex + 1);
        parsedUrl.hostname = hostnameWithoutCredentials;
    }

    // Remove username from the path
    const pathIndex = pathname.indexOf('@');
    if (pathIndex !== -1) {
        const pathnameWithoutCredentials = pathname.substring(pathIndex + 1);
        parsedUrl.pathname = pathnameWithoutCredentials;
    }

    // Remove username and password from the search parameters
    const searchParams = new URLSearchParams(search);
    searchParams.delete('username');
    searchParams.delete('password');
    parsedUrl.search = searchParams.toString();

    return `${protocol}://${hostname}${pathname}${search}${hash}`;
}

